"use client";
import { useState, useEffect, useCallback } from "react";

export function useSpeech() {
  const [voices, setVoices] = useState([]);
  const [speaking, setSpeaking] = useState(false);

  useEffect(() => {
    if (typeof window === "undefined") return;

    const loadVoices = () => {
      const allVoices = window.speechSynthesis.getVoices();
      setVoices(allVoices);
    };

    loadVoices();
    window.speechSynthesis.onvoiceschanged = loadVoices;

    return () => {
      window.speechSynthesis.onvoiceschanged = null;
    };
  }, []);

  // Detect language based on unicode ranges
  const detectLanguage = (text) => {
    if (/[\u0900-\u097F]/.test(text)) return "hi-IN"; // Hindi
    if (/[\u0B80-\u0BFF]/.test(text)) return "ta-IN"; // Tamil
    if (/[\u0C00-\u0C7F]/.test(text)) return "te-IN"; // Telugu
    if (/[\u0A00-\u0A7F]/.test(text)) return "gu-IN"; // Gujarati
    if (/[\u0C80-\u0CFF]/.test(text)) return "kn-IN"; // Kannada
    if (/[\u0D00-\u0D7F]/.test(text)) return "ml-IN"; // Malayalam
    return "en-IN"; // Default English
  };

  const getBestFemaleVoice = (lang) => {
    const femaleVoice =
      voices.find(
        (v) =>
          v.lang.includes(lang.split("-")[0]) &&
          /female|zira|google|wavenet/i.test(v.name)
      ) ||
      voices.find((v) => v.lang.includes(lang.split("-")[0])) ||
      voices[0];

    return femaleVoice;
  };

  const speak = useCallback(
    (text, forcedLang = null) => {
      if (!text) return;

      // Clean text to avoid speaking unnecessary filler words
      const sanitizeForSpeech = (raw) => {
        if (!raw) return raw;
        let s = String(raw);

        // Remove common filler words the user reported and some disfluencies
        s = s.replace(/\b(um+|uh+|hmm+|aal|aal+|erm)\b/gi, "");

        // Remove the literal word "dot" when used as filler (e.g. "example dot com")
        s = s.replace(/\bdot\b/gi, "");

        // Normalize hashtags: remove leading '#' but keep the tag text ("#topic" -> "topic")
        s = s.replace(/#([^\s#]+)/g, "$1");

        // Remove the literal word "hashtag" if the model spelled it out
        s = s.replace(/\bhashtag\b/gi, "");

        // Remove common variants like "hash tag", "hash-tag", or "hash_tag"
        s = s.replace(/\bhash[\s-_]?tag\b/gi, "");

        // Remove any remaining stray '#' characters
        s = s.replace(/#/g, "");

        // Remove standalone tokens that are just 'hash' or 'tag' or common mis-heard variants
        s = s.replace(/\b(?:hash(?:[\s-_]?tag)?|hash|tag|shatga|shatg)\b/gi, "");

        // Remove ellipses and multiple dots
        s = s.replace(/\.{2,}/g, " ");

        // Remove single dots/periods that are not part of decimal numbers
        try {
          s = s.replace(/(?<!\d)\.(?!\d)/g, " ");
        } catch (e) {
          // Fallback for environments without lookbehind support: remove dots except between digits
          s = s.replace(/\.(?=\D|$)/g, " ");
          s = s.replace(/(?<=^|\D)\./g, " ");
        }

        // Remove literal words like 'period' or 'full stop' if spoken
        s = s.replace(/\b(period|full stop|full-stop|fullstop)\b/gi, "");

        // Remove asterisks and their spoken forms
        s = s.replace(/\*/g, "");
        s = s.replace(/\b(asterisk|asterisks|astracs|astracks|asterix|asterixs|astiracs)\b/gi, "");

        // Normalize multiple spaces and trim
        s = s.replace(/\s{2,}/g, " ").trim();

        return s;
      };

      const cleaned = sanitizeForSpeech(text);

      window.speechSynthesis.cancel();

      const lang = forcedLang || detectLanguage(text);
      const utterance = new SpeechSynthesisUtterance(cleaned);
      const voice = getBestFemaleVoice(lang);

      if (voice) {
        utterance.voice = voice;
        utterance.lang = voice.lang;
      }

      utterance.rate = 0.9;
      utterance.pitch = 1.2;
      utterance.volume = 1;

      utterance.onstart = () => setSpeaking(true);
      utterance.onend = () => setSpeaking(false);

      window.speechSynthesis.speak(utterance);
    },
    [voices]
  );

  const stop = useCallback(() => {
    if (typeof window === "undefined") return;
    try {
      window.speechSynthesis.cancel();
    } catch {}
    setSpeaking(false);
  }, []);

  return { speak, detectLanguage, speaking, stop };
}